package com.lightevents.destinations;
import com.lightevents.auth.AccountService; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/destinations")
public class DestinationSpotController { private final DestinationSpotRepository repo; private final AccountService accounts; public DestinationSpotController(DestinationSpotRepository repo, AccountService accounts){this.repo=repo;this.accounts=accounts;} @GetMapping public List<DestinationSpot> list(){return repo.findAllByOrderBySortOrderAscTitleAsc();} @PostMapping public DestinationSpot create(@RequestHeader(value="X-LightEvents-Token", required=false) String token, @RequestBody DestinationSpot s){ accounts.requireAdmin(token); return repo.save(s);} @PutMapping("/{id}") public DestinationSpot update(@RequestHeader(value="X-LightEvents-Token", required=false) String token,@PathVariable Long id,@RequestBody DestinationSpot s){ accounts.requireAdmin(token); DestinationSpot d=repo.findById(id).orElseThrow(); d.setTitle(s.getTitle()); d.setCity(s.getCity()); d.setCountry(s.getCountry()); d.setCountryCode(s.getCountryCode()); d.setImageUrl(s.getImageUrl()); d.setSortOrder(s.getSortOrder()); return repo.save(d);} @DeleteMapping("/{id}") public void delete(@RequestHeader(value="X-LightEvents-Token", required=false) String token,@PathVariable Long id){ accounts.requireAdmin(token); repo.deleteById(id);} }
